const inp=$input.first().json||{};
function dig(x){
  if(x==null) return '';
  if(typeof x==='string') return x;
  if(typeof x==='object'){
    if(x.action!==undefined) return x;
    for(const k of ['some_input','query','input','text','value']) if(x[k]!==undefined) return dig(x[k]);
    const vals=Object.values(x); if(vals.length) return dig(vals[0]);
  }
  return '';
}
let dug=dig(inp), action='', name='';
if(dug&&typeof dug==='object'&&dug.action!==undefined){ action=dug.action; name=dug.name||''; }
else {
  let s=String(dug||'').trim();
  if(s.startsWith('{')){ try{const o=JSON.parse(s); action=o.action||''; name=o.name||'';}catch(e){} }
  if(!action){ const p=s.split(/\s+/); action=(p[0]||''); name=p.slice(1).join(' '); }
}
action=String(action||'').trim().toLowerCase();
if(action==='config'||action==='ossec.conf'||action==='conf') action='ossec';
if(action==='list'||action==='liste') action='scripts';
if(!['ossec','scripts','script'].includes(action)){ if(name===''&&action){ name=action; action='script'; } else action='scripts'; }
name=String(name||'').replace(/[^A-Za-z0-9._-]/g,'').slice(0,64);
const fs=require('fs'); const base='/home/node/.n8n/socview'; let result='';
try{
  if(action==='ossec') result=fs.readFileSync(base+'/ossec.conf','utf8');
  else if(action==='scripts') result="Scripts d'action disponibles:\n"+fs.readdirSync(base+'/scripts').sort().join('\n');
  else { if(!name) result='Precise: action=script name=<nom>. Liste via action=scripts.';
         else { try{ result=fs.readFileSync(base+'/scripts/'+name,'utf8'); }catch(e){ result='Script introuvable: '+name+'. Liste via action=scripts.'; } } }
}catch(e){ result='[erreur] '+e.message; }
if(result.length>14000) result=result.slice(0,14000)+'\n...[tronque]';
return [{json:{result: result||'(vide)'}}];
